 291 |         .op-row {
 292 |             padding: 10px 12px; border-bottom: 1px solid #222; font-size: 11px;
 293 |             display: flex; flex-direction: column; gap: 4px; cursor: pointer; transition: background 0.1s;
 294 |         }
 295 |         .op-row:last-child { border-bottom: none; }
 296 |         .op-row:hover { background: #1a1a1c; }
 297 |         .op-row.row-fail { border-left: 3px solid var(--danger); background: rgba(239, 68, 68, 0.05); }
 298 |         .op-title { color: #fff; font-weight: 600; display: flex; justify-content: space-between; }
 299 |         .op-details { color: #888; white-space: pre-wrap; margin-top: 2px; overflow-wrap: anywhere; word-break: break-word; }
 300 |         .score-badge { font-size: 9px; padding: 1px 4px; border-radius: 3px; border: 1px solid #444; }
 301 |         
 302 |         .op-options { display: none; padding: 8px 12px; background: #0f0f11; gap: 8px; border-bottom: 1px solid #222; animation: fadeUp 0.1s; }
 303 |         .op-options.show { display: flex; }
 304 |         .op-opt-btn { flex: 1; padding: 8px; border: 1px solid var(--border); background: var(--card-bg); color: var(--text-muted); font-size: 11px; border-radius: 6px; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 6px; }
 305 |         .op-opt-btn:hover { background: #222; color: white; }
