7924 |     function extractTableNames(sql) {
7925 |         if (!sql) return [];
7926 |         const tables = [];
7927 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7928 |         
7929 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7930 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7931 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7932 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7933 | 
7934 |         let match;
7935 |         while ((match = fromRegex.exec(sql)) !== null) {
7936 |             const name = match[1];
7937 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7938 |                 tables.push(name);
7939 |             }
7940 |         }
7941 |         
7942 |         while ((match = metaRegex.exec(sql)) !== null) {
7943 |             const name = match[1];
7944 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7945 |                 tables.push(name);
7946 |             }
7947 |         }
7948 | 
7949 |         return tables;
7950 |     }
7951 | 
7952 |     function convertToCSV(resultObj) {
7953 |         const data = resultObj.data || [];
7954 |         if (!data.length) return '';
7955 |         
7956 |         const tables = extractTableNames(resultObj.sql);
7957 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7958 | 
7959 |         const headers = Object.keys(data[0]);
7960 |         const rows = data.map(row => 
7961 |             headers.map(header => {
7962 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7963 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7964 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7965 |             }).join(',')
7966 |         );
7967 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7968 |     }
