2278 |     // --- CLIENT SIDE PATCH ENGINE (Smart Line-Matcher) ---
2279 |     function applyLocalPatch(content, ops) {
2280 |         let lines = content.split('\n');
2281 |         let logs = [];
2282 |         let success = true;
2283 | 
2284 |         if (typeof ops === 'string') {
2285 |             try { ops = JSON.parse(ops); } catch(e) { return { content, success: false, logs: ["Invalid JSON"]}; }
2286 |         }
2287 | 
2288 |         ops.forEach(op => {
2289 |             if (op.action === 'comment') return;
2290 |             if (op.action === 'create_file') { lines = op.content.split('\n'); logs.push('Created file'); return; }
2291 |             
2292 |             if (op.action === 'replace_block') {
2293 |                 // Strategy 1: Exact String Match (Fastest)
2294 |                 const currentStr = lines.join('\n');
2295 |                 if (currentStr.includes(op.find_block)) {
2296 |                     lines = currentStr.replace(op.find_block, op.replace_with).split('\n');
2297 |                     logs.push('Exact match applied');
2298 |                     return;
2299 |                 }
2300 | 
2301 |                 // Strategy 2: Line-by-Line Fuzzy Match (Whitespace Agnostic)
2302 |                 const searchLines = op.find_block.split('\n').map(l => l.trim()).filter(l => l !== '');
2303 |                 if (searchLines.length === 0) return;
2304 | 
2305 |                 let matchStart = -1;
2306 |                 let matchEnd = -1;
2307 | 
2308 |                 // Scan file lines
2309 |                 for (let i = 0; i < lines.length; i++) {
2310 |                     // If first line matches (ignoring whitespace)
2311 |                     if (lines[i].trim() === searchLines[0]) {
2312 |                         // Check subsequent lines
2313 |                         let allMatch = true;
2314 |                         let fileOffset = 0;
2315 |                         let searchOffset = 1;
2316 |                         
2317 |                         while (searchOffset < searchLines.length) {
2318 |                             if (i + fileOffset + 1 >= lines.length) { allMatch = false; break; }
2319 |                             const nextFile = lines[i + fileOffset + 1].trim();
2320 |                             // Skip empty lines in file if they aren't in search block
2321 |                             if (nextFile === '') {
2322 |                                 fileOffset++;
2323 |                                 continue;
2324 |                             }
2325 |                             if (nextFile !== searchLines[searchOffset]) {
2326 |                                 allMatch = false;
2327 |                                 break;
2328 |                             }
2329 |                             fileOffset++;
2330 |                             searchOffset++;
2331 |                         }
2332 | 
2333 |                         if (allMatch) {
2334 |                             matchStart = i;
2335 |                             matchEnd = i + fileOffset;
2336 |                             break;
2337 |                         }
2338 |                     }
2339 |                 }
2340 | 
2341 |                 if (matchStart !== -1) {
2342 |                     // Replace the range of lines
2343 |                     const replacement = op.replace_with.split('\n');
2344 |                     lines.splice(matchStart, (matchEnd - matchStart) + 1, ...replacement);
2345 |                     logs.push(`Fuzzy match applied (Lines ${matchStart+1}-${matchEnd+1})`);
2346 |                 } else {
2347 |                     success = false;
2348 |                     logs.push(`Failed to find block: "${op.find_block.substring(0, 30)}..."`);
2349 |                     console.warn("Patch Mismatch. File has:", content.substring(0, 200), "... vs Search:", op.find_block);
2350 |                 }
2351 |             }
2352 |         });
2353 |         return { content: lines.join('\n'), success, logs };
2354 |     }
