5194 |         if (seconds < 10) return 'just now';
5195 |         if (seconds < 60) return seconds + 's ago';
5196 |         const minutes = Math.floor(seconds / 60);
5197 |         if (minutes < 60) return minutes + 'm ago';
5198 |         const hours = Math.floor(minutes / 60);
5199 |         if (hours < 24) return hours + 'h ago';
5200 |         return date.toLocaleDateString();
