7913 |     function extractTableNames(sql) {
7914 |         if (!sql) return [];
7915 |         const tables = [];
7916 |         const systemNoise = ['columns', 'tables', 'schemata', 'information_schema'];
7917 |         
7918 |         // Pattern 1: Standard FROM/JOIN (handles schema.table and "table")
7919 |         const fromRegex = /(?:FROM|JOIN)\s+(?:(?:"?\w+"?\.)?"?(\w+)"?)/gi;
7920 |         // Pattern 2: Metadata queries (WHERE table_name = '...')
7921 |         const metaRegex = /table_name\s*=\s*'([^']+)'/gi;
7922 | 
7923 |         let match;
7924 |         while ((match = fromRegex.exec(sql)) !== null) {
7925 |             const name = match[1];
7926 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7927 |                 tables.push(name);
7928 |             }
7929 |         }
7930 |         
7931 |         while ((match = metaRegex.exec(sql)) !== null) {
7932 |             const name = match[1];
7933 |             if (name && !tables.includes(name) && !systemNoise.includes(name.toLowerCase())) {
7934 |                 tables.push(name);
7935 |             }
7936 |         }
7937 | 
7938 |         return tables;
7939 |     }
7940 | 
7941 |     function convertToCSV(resultObj) {
7942 |         const data = resultObj.data || [];
7943 |         if (!data.length) return '';
7944 |         
7945 |         const tables = extractTableNames(resultObj.sql);
7946 |         const metaHeader = tables.length > 0 ? `# Source Tables: ${tables.join(', ')}\n# Export Date: ${new Date().toISOString()}\n` : '';
7947 | 
7948 |         const headers = Object.keys(data[0]);
7949 |         const rows = data.map(row => 
7950 |             headers.map(header => {
7951 |                 let cell = row[header] === null || row[header] === undefined ? '' : row[header];
7952 |                 if (typeof cell === 'object') cell = JSON.stringify(cell);
7953 |                 return '"' + String(cell).replace(/"/g, '""') + '"';
7954 |             }).join(',')
7955 |         );
7956 |         return metaHeader + [headers.join(','), ...rows].join('\n');
7957 |     }
